() => {
  // Try to find any text showing a count of profiles
  const all = document.body.innerText;
  // Look for patterns like "X profiles" or "Showing X"
  const matches = all.match(/([\d,]+)\s*(profiles?|subscribers?|results?)/gi);
  const heading = [...document.querySelectorAll('h1,h2,h3,[data-testid]')].map(e => e.textContent.trim()).filter(Boolean).slice(0, 10);
  const countEls = [...document.querySelectorAll('[class*="count"],[class*="total"],[class*="result"]')].map(e => e.textContent.trim()).filter(Boolean).slice(0, 10);
  return { url: location.href, matches, heading, countEls, bodySnippet: all.slice(0, 2000) };
}

